import { useEffect, useState } from 'react';
import api from '../Api';

function Events() {
  const [events, setEvents] = useState([]);

  useEffect(() => {
    fetchEvents();
  }, []);

  const fetchEvents = async () => {
    const res = await api.get('events/');
    setEvents(res.data);
  };

  return (
    <div>
      <h1>Events</h1>

      {events.map((event) => (
        <div key={event.id}>
          <h3>{event.title}</h3>
          <p>{event.description}</p>
        </div>
      ))}
    </div>
  );
}

export default Events;
